class LRParser:
 def __init__(self, parsing_table):
 self.parsing_table = parsing_table
 self.stack = ['s0']

 def parse(self, input_string):
 ip = 0
 while ip < len(input_string):
 s = self.stack[-1]
 a = input_string[ip]
 action = self.parsing_table[s][a]
 if action == 'shift':
 self.stack.append(a)
 self.stack.append(action[1])
 ip += 1
 elif action == 'reduce':
 production = action[1]
 self.stack.pop(2 * len(production))
 self.stack.append(production[0])
 self.stack.append(self.parsing_table[self.stack[-2]][production[0]])
 print(production)
 elif action == 'accept':
 return True
 else:
 return False
 return False

#include <stdio.h>
#include <stdlib.h>

#define MAX_STACK_SIZE 100

typedef struct {
 char state;
 char symbol;
} stack_element;

stack_element stack[MAX_STACK_SIZE];
int top = -1;

void push(char state, char symbol) {
 if (top >= MAX_STACK_SIZE - 1) {
 printf("Stack overflow\n");
 exit(1);
 }
 stack[++top].state = state;
 stack[top].symbol = symbol;
}

void pop() {
 if (top < 0) {
 printf("Stack underflow\n");
 exit(1);
 }
 top--;
}

